APP_NAME = "office_face_recognition_api"
DEFAULT_MODEL_DIR = os.environ.get("MODEL_DIR", "./model_store")
DEFAULT_TRAIN_DIR = os.environ.get("TRAIN_DIR", "./training_images")
DEFAULT_MODEL_PATH = os.environ.get("MODEL_PATH", os.path.join(DEFAULT_MODEL_DIR, "model.npz"))

FACE_ENCODER_MODEL = os.environ.get("FACE_ENCODER_MODEL", "small")  # "small" or "large"
UPSAMPLE_TIMES = int(os.environ.get("UPSAMPLE_TIMES", "1"))
DETECTION_MODEL = os.environ.get("DETECTION_MODEL", "hog")  # "hog" or "cnn"
JITTERS = int(os.environ.get("JITTERS", "1"))

MIN_IMAGES_PER_CLASS = int(os.environ.get("MIN_IMAGES_PER_CLASS", "1"))
MIN_CLASSES = int(os.environ.get("MIN_CLASSES", "2"))
MIN_TOTAL_IMAGES = int(os.environ.get("MIN_TOTAL_IMAGES", "2"))

ALLOWED_IMAGE_EXT = {".jpg", ".jpeg", ".png", ".bmp", ".tif", ".tiff", ".webp"}

MODEL_LOCK = threading.RLock()


def _now_ms() -> int:
    return int(time.time() * 1000)


def _safe_mkdir(path: str) -> None:
    os.makedirs(path, exist_ok=True)


def _read_image_bytes(data: bytes) -> np.ndarray:
    try:
        img = Image.open(io.BytesIO(data))
        img = ImageOps.exif_transpose(img)
        img = img.convert("RGB")
        return np.array(img)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image data")


def _list_training_images(train_dir: str) -> List[Tuple[str, str]]:
    pairs = []
    if not os.path.isdir(train_dir):
        return pairs
    for name in sorted(os.listdir(train_dir)):
        cls_dir = os.path.join(train_dir, name)
        if not os.path.isdir(cls_dir):
            continue
        for root, _, files in os.walk(cls_dir):
            for fn in sorted(files):
                ext = os.path.splitext(fn)[1].lower()
                if ext in ALLOWED_IMAGE_EXT:
                    pairs.append((name, os.path.join(root, fn)))
    return pairs


def _compute_image_digest(path: str) -> str:
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _softmax(x: np.ndarray) -> np.ndarray:
    x = np.asarray(x, dtype=np.float64)
    x = x - np.max(x)
    expx = np.exp(x)
    s = expx / np.sum(expx)
    return s.astype(np.float64)


def _stable_probs_from_svc(
    clf: SVC, X: np.ndarray, class_names: List[str]
) -> np.ndarray:
    if hasattr(clf, "predict_proba") and getattr(clf, "probability", False):
        p = clf.predict_proba(X)
        if p.shape[1] != len(class_names):
            full = np.zeros((p.shape[0], len(class_names)), dtype=np.float64)
            idx_map = {c: i for i, c in enumerate(clf.classes_)}
            for j, c in enumerate(class_names):
                if c in idx_map:
                    full[:, j] = p[:, idx_map[c]]
            p = full
        p = np.clip(p, 0.0, 1.0)
        row_sums = np.sum(p, axis=1, keepdims=True)
        row_sums[row_sums == 0] = 1.0
        return (p / row_sums).astype(np.float64)
    if hasattr(clf, "decision_function"):
        scores = clf.decision_function(X)
        if scores.ndim == 1:
            scores = np.vstack([-scores, scores]).T
        if scores.shape[1] != len(class_names):
            full = np.zeros((scores.shape[0], len(class_names)), dtype=np.float64)
            idx_map = {c: i for i, c in enumerate(clf.classes_)}
            for j, c in enumerate(class_names):
                if c in idx_map:
                    full[:, j] = scores[:, idx_map[c]]
            scores = full
        probs = np.vstack([_softmax(row) for row in scores])
        return probs.astype(np.float64)
    raise RuntimeError("Classifier does not support probability or decision scores")


def _find_face_encodings(
    rgb: np.ndarray,
    max_faces: int = 10,
) -> Tuple[List[np.ndarray], List[Tuple[int, int, int, int]]]:
    locations = face_recognition.face_locations(
        rgb, number_of_times_to_upsample=UPSAMPLE_TIMES, model=DETECTION_MODEL
    )
    if not locations:
        return [], []
    if len(locations) > max_faces:
        locations = locations[:max_faces]
    encs = face_recognition.face_encodings(
        rgb, known_face_locations=locations, num_jitters=JITTERS, model=FACE_ENCODER_MODEL
    )
    encs = [np.asarray(e, dtype=np.float32) for e in encs]
    return encs, locations


class TrainRequest(BaseModel):
    train_dir: str = Field(default=DEFAULT_TRAIN_DIR)
    model_path: str = Field(default=DEFAULT_MODEL_PATH)
    force: bool = Field(default=False)
    min_images_per_class: int = Field(default=MIN_IMAGES_PER_CLASS)
    min_classes: int = Field(default=MIN_CLASSES)
    min_total_images: int = Field(default=MIN_TOTAL_IMAGES)


class PredictResponse(BaseModel):
    model_version: int
    model_updated_ms: int
    num_classes: int
    classes: List[str]
    faces: List[Dict]
    timing_ms: Dict[str, int]


class ModelState:
    def __init__(self):
        self.clf: Optional[SVC] = None
        self.classes: List[str] = []
        self.model_version: int = 0
        self.updated_ms: int = 0
        self.model_path: str = DEFAULT_MODEL_PATH
        self.train_fingerprint: str = ""

    def is_ready(self) -> bool:
        return self.clf is not None and len(self.classes) > 0

    def to_disk(self, path: str, fingerprint: str) -> None:
        _safe_mkdir(os.path.dirname(path))
        classes_arr = np.array(self.classes, dtype=object)
        np.savez_compressed(
            path,
            classes=classes_arr,
            model_version=np.array([self.model_version], dtype=np.int64),
            updated_ms=np.array([self.updated_ms], dtype=np.int64),
            fingerprint=np.array([fingerprint], dtype=object),
            clf_pickle=np.array([json.dumps(_pickle_sklearn(self.clf))], dtype=object),
        )

    def from_disk(self, path: str) -> bool:
        if not os.path.isfile(path):
            return False
        try:
            d = np.load(path, allow_pickle=True)
            classes = d["classes"].tolist()
            model_version = int(d["model_version"][0])
            updated_ms = int(d["updated_ms"][0])
            fingerprint = str(d["fingerprint"][0])
            clf_payload = json.loads(str(d["clf_pickle"][0]))
            clf = _unpickle_sklearn(clf_payload)
            self.clf = clf
            self.classes = list(classes)
            self.model_version = model_version
            self.updated_ms = updated_ms
            self.train_fingerprint = fingerprint
            self.model_path = path
            return True
        except Exception:
            return False


def _pickle_sklearn(obj) -> Dict:
    import pickle
    b = pickle.dumps(obj, protocol=pickle.HIGHEST_PROTOCOL)
    return {"b64": _b64e(b)}


def _unpickle_sklearn(payload: Dict):
    import pickle
    b = _b64d(payload["b64"])
    return pickle.loads(b)


def _b64e(b: bytes) -> str:
    import base64
    return base64.b64encode(b).decode("ascii")


def _b64d(s: str) -> bytes:
    import base64
    return base64.b64decode(s.encode("ascii"))


STATE = ModelState()
app = FastAPI(title=APP_NAME)


def _compute_training_fingerprint(pairs: List[Tuple[str, str]]) -> str:
    h = hashlib.sha256()
    for cls, path in pairs:
        h.update(cls.encode("utf-8"))
        h.update(b"\0")
        st = os.stat(path)
        h.update(str(st.st_mtime_ns).encode("utf-8"))
        h.update(b"\0")
        h.update(str(st.st_size).encode("utf-8"))
        h.update(b"\0")
        h.update(os.path.basename(path).encode("utf-8"))
        h.update(b"\0")
    return h.hexdigest()


def _train_from_dir(
    train_dir: str,
    min_images_per_class: int,
    min_classes: int,
    min_total_images: int,
) -> Tuple[SVC, List[str], Dict]:
    pairs = _list_training_images(train_dir)
    if len(pairs) < min_total_images:
        raise HTTPException(status_code=400, detail=f"Not enough training images (found {len(pairs)}).")

    X = []
    y = []
    per_class_counts = {}
    skipped = []
    processed = 0
    faces_found = 0

    for cls, path in pairs:
        processed += 1
        try:
            with open(path, "rb") as f:
                rgb = _read_image_bytes(f.read())
            encs, _locs = _find_face_encodings(rgb, max_faces=2)
            if len(encs) == 0:
                skipped.append({"class": cls, "path": path, "reason": "no_face"})
                continue
            if len(encs) > 1:
                skipped.append({"class": cls, "path": path, "reason": "multiple_faces"})
                continue
            X.append(encs[0])
            y.append(cls)
            faces_found += 1
            per_class_counts[cls] = per_class_counts.get(cls, 0) + 1
        except HTTPException:
            skipped.append({"class": cls, "path": path, "reason": "invalid_image"})
        except Exception:
            skipped.append({"class": cls, "path": path, "reason": "error"})

    valid_classes = sorted([c for c, n in per_class_counts.items() if n >= min_images_per_class])
    if len(valid_classes) < min_classes:
        raise HTTPException(
            status_code=400,
            detail=f"Not enough classes with >= {min_images_per_class} images (found {len(valid_classes)}).",
        )

    X2 = []
    y2 = []
    for xi, yi in zip(X, y):
        if yi in valid_classes:
            X2.append(xi)
            y2.append(yi)

    Xn = normalize(np.asarray(X2, dtype=np.float32))
    y_arr = np.asarray(y2, dtype=object)

    clf = SVC(kernel="linear", probability=True, class_weight="balanced")
    clf.fit(Xn, y_arr)

    meta = {
        "train_dir": train_dir,
        "processed_files": processed,
        "faces_used": int(Xn.shape[0]),
        "classes_used": valid_classes,
        "per_class_counts": {c: int(per_class_counts.get(c, 0)) for c in valid_classes},
        "skipped": skipped,
    }
    return clf, valid_classes, meta


@app.on_event("startup")
def _startup_load():
    _safe_mkdir(DEFAULT_MODEL_DIR)
    with MODEL_LOCK:
        STATE.from_disk(DEFAULT_MODEL_PATH)


@app.get("/health")
def health():
    with MODEL_LOCK:
        return {
            "ok": True,
            "model_ready": STATE.is_ready(),
            "num_classes": len(STATE.classes),
            "model_version": STATE.model_version,
            "updated_ms": STATE.updated_ms,
            "model_path": STATE.model_path,
        }


@app.post("/train")
def train(req: TrainRequest = Body(default=TrainRequest())):
    t0 = _now_ms()
    train_dir = req.train_dir
    model_path = req.model_path

    pairs = _list_training_images(train_dir)
    fingerprint = _compute_training_fingerprint(pairs)

    with MODEL_LOCK:
        if (not req.force) and STATE.is_ready() and STATE.train_fingerprint == fingerprint and STATE.model_path == model_path:
            return {
                "trained": False,
                "reason": "no_change",
                "model_version": STATE.model_version,
                "updated_ms": STATE.updated_ms,
                "num_classes": len(STATE.classes),
                "classes": STATE.classes,
                "timing_ms": {"total": _now_ms() - t0},
            }

    clf, classes, meta = _train_from_dir(
        train_dir=train_dir,
        min_images_per_class=req.min_images_per_class,
        min_classes=req.min_classes,
        min_total_images=req.min_total_images,
    )

    with MODEL_LOCK:
        STATE.clf = clf
        STATE.classes = list(classes)
        STATE.model_version += 1
        STATE.updated_ms = _now_ms()
        STATE.model_path = model_path
        STATE.train_fingerprint = fingerprint
        STATE.to_disk(model_path, fingerprint)

    return {
        "trained": True,
        "model_version": STATE.model_version,
        "updated_ms": STATE.updated_ms,
        "num_classes": len(STATE.classes),
        "classes": STATE.classes,
        "meta": meta,
        "timing_ms": {"total": _now_ms() - t0},
    }


@app.post("/predict", response_model=PredictResponse)
async def predict(image: UploadFile = File(...), max_faces: int = 5):
    t0 = _now_ms()
    data = await image.read()
    rgb = _read_image_bytes(data)
    t1 = _now_ms()

    with MODEL_LOCK:
        if not STATE.is_ready():
            raise HTTPException(status_code=503, detail="Model not trained. Call /train first.")
        clf = STATE.clf
        classes = list(STATE.classes)
        model_version = STATE.model_version
        updated_ms = STATE.updated_ms

    encs, locs = _find_face_encodings(rgb, max_faces=max_faces)
    t2 = _now_ms()

    faces_out = []
    if len(encs) > 0:
        X = normalize(np.asarray(encs, dtype=np.float32))
        probs = _stable_probs_from_svc(clf, X, classes)
        for i, (p, loc) in enumerate(zip(probs, locs)):
            dist = {cls: float(pj) for cls, pj in zip(classes, p.tolist())}
            top_idx = int(np.argmax(p))
            faces_out.append(
                {
                    "face_index": i,
                    "location": {"top": int(loc[0]), "right": int(loc[1]), "bottom": int(loc[2]), "left": int(loc[3])},
                    "top_class": classes[top_idx],
                    "top_score": float(p[top_idx]),
                    "distribution": dist,
                }
            )

    t3 = _now_ms()
    return PredictResponse(
        model_version=model_version,
        model_updated_ms=updated_ms,
        num_classes=len(classes),
        classes=classes,
        faces=faces_out,
        timing_ms={"decode": t1 - t0, "detect_encode": t2 - t1, "classify": t3 - t2, "total": t3 - t0},
    )


@app.get("/classes")
def get_classes():
    with MODEL_LOCK:
        if not STATE.is_ready():
            return {"classes": [], "num_classes": 0, "model_ready": False}
        return {"classes": STATE.classes, "num_classes": len(STATE.classes), "model_ready": True}


@app.post("/reload")
def reload_model(model_path: str = Body(default=DEFAULT_MODEL_PATH, embed=True)):
    with MODEL_LOCK:
        ok = STATE.from_disk(model_path)
        if not ok:
            raise HTTPException(status_code=404, detail="Model file not found or invalid.")
        STATE.model_path = model_path
        return {
            "reloaded": True,
            "model_version": STATE.model_version,
            "updated_ms": STATE.updated_ms,
            "num_classes": len(STATE.classes),
            "classes": STATE.classes,
            "model_path": STATE.model_path,
        }


